    defer _gui_active_backend.deinitFn();
    const _g = GuiContext{ ._b = &_gui_active_backend };
    if (comptime @typeInfo(@TypeOf(frame)) == .@"fn") {
        while (_gui_active_backend.newFrameFn()) {
            frame(_g);
            _gui_active_backend.endFrameFn();
        }
    } else {
        var _mframe = frame;
        while (_gui_active_backend.newFrameFn()) {
            _mframe.call(_g);
            _gui_active_backend.endFrameFn();
        }
    }
}
